    private readonly RegisterUserDto _registerDto = new();
    private string _confirmPassword = "";
    private bool _acceptTerms = false;
    private bool _isLoading = false;

    private async Task HandleRegister()
    {
        if (_confirmPassword != _registerDto.Password)
        {
            Snackbar.Add("Passwörter stimmen nicht überein", Severity.Error);
            return;
        }

        if (!_acceptTerms)
        {
            Snackbar.Add("Bitte akzeptieren Sie die Nutzungsbedingungen", Severity.Error);
            return;
        }

        try
        {
            _isLoading = true;
            var result = await AuthService.RegisterAsync(_registerDto);

            if (result.IsSuccess)
            {
                Snackbar.Add("Account erfolgreich erstellt! Sie können sich nun anmelden.", Severity.Success);
                Navigation.NavigateTo("/login");
            }
            else
            {
                Snackbar.Add($"Registrierung fehlgeschlagen: {result.Error}", Severity.Error);
            }
        }
        catch (Exception ex)
        {
            Snackbar.Add($"Ein Fehler ist aufgetreten: {ex.Message}", Severity.Error);
        }
        finally
        {
            _isLoading = false;
        }
    }

    protected override async Task OnInitializedAsync()
    {
        if (await AuthService.IsAuthenticatedAsync())
        {
            Navigation.NavigateTo("/dashboard");
        }
    }

